// src/routes/stats.ts
var statsRoutes = new Elysia({ prefix: "/stats" }).use(authMiddleware).get("/today", async (ctx) => {
  const { getCurrentUser } = ctx;
  const user = getCurrentUser();
  const today = new Date;
  const todayStart = startOfDay(today);
  const todayEnd = endOfDay(today);
  const [totalTasksResult] = await db.select({ count: count() }).from(tasks).where(and(eq(tasks.userId, user.userId), gte(tasks.createdAt, todayStart), lte(tasks.createdAt, todayEnd)));
  const [completedTasksResult] = await db.select({ count: count() }).from(tasks).where(and(eq(tasks.userId, user.userId), eq(tasks.status, "completed"), gte(tasks.completedAt, todayStart), lte(tasks.completedAt, todayEnd)));
  const [pendingTasksResult] = await db.select({ count: count() }).from(tasks).where(and(eq(tasks.userId, user.userId), eq(tasks.status, "pending"), lte(tasks.dueDate, todayEnd)));
  const total = totalTasksResult?.count || 0;
  const completed = completedTasksResult?.count || 0;
  const pending = pendingTasksResult?.count || 0;
  const completionRate = total > 0 ? Math.round(completed / total * 100) : 0;
  return {
    success: true,
    data: {
      total,
      completed,
      pending,
      completionRate
    }
  };
}).get("/summary", async (ctx) => {
  const { getCurrentUser, query } = ctx;
  const user = getCurrentUser();
  const { period = "week" } = query;
  const now = new Date;
  let startDate;
  let endDate;
  switch (period) {
    case "day":
      startDate = startOfDay(now);
      endDate = endOfDay(now);
      break;
    case "week":
      startDate = startOfWeek(now, { weekStartsOn: 1 });
      endDate = endOfWeek(now, { weekStartsOn: 1 });
      break;
    case "month":
      startDate = startOfMonth(now);
      endDate = endOfMonth(now);
      break;
    default:
      startDate = startOfWeek(now, { weekStartsOn: 1 });
      endDate = endOfWeek(now, { weekStartsOn: 1 });
  }
  const [totalTasksResult] = await db.select({ count: count() }).from(tasks).where(and(eq(tasks.userId, user.userId), gte(tasks.createdAt, startDate), lte(tasks.createdAt, endDate)));
  const [completedTasksResult] = await db.select({ count: count() }).from(tasks).where(and(eq(tasks.userId, user.userId), eq(tasks.status, "completed"), gte(tasks.completedAt, startDate), lte(tasks.completedAt, endDate)));
  const total = totalTasksResult?.count || 0;
  const completed = completedTasksResult?.count || 0;
  const completionRate = total > 0 ? Math.round(completed / total * 100) : 0;
  return {
    success: true,
    data: {
      period,
      startDate,
      endDate,
      totalTasks: total,
      completedTasks: completed,
      completionRate
    }
  };
}, {
  query: t.Object({
    period: t.Optional(t.Enum({ day: "day", week: "week", month: "month" }))
  })
}).get("/trend", async (ctx) => {
  const { getCurrentUser, query } = ctx;
  const user = getCurrentUser();
  const { days = 7 } = query;
  const now = new Date;
  const startDate = subDays(startOfDay(now), days - 1);
  const stats = await db.select().from(dailyStats).where(and(eq(dailyStats.userId, user.userId), gte(dailyStats.date, startDate))).orderBy(desc(dailyStats.date));
  return {
    success: true,
    data: {
      days,
      stats
    }
  };
}, {
  query: t.Object({
    days: t.Optional(t.Number({ minimum: 1, maximum: 30 }))
  })
});

// src/index.ts
var PORT = parseInt(process.env.PORT || "3000", 10);
var app = new Elysia().use(cors()).get("/", () => ({
  name: "Taro Todo API",
  version: "1.0.0",
  status: "ok"
})).get("/health", () => ({ status: "healthy", timestamp: new Date().toISOString() })).group(API_BASE_PATH, (group) => group.use(authRoutes).use(tasksRoutes).use(usersRoutes).use(statsRoutes)).onError(({ code, error, set }) => {
  const errorMessage = "message" in error ? error.message : String(error);
  console.error(`[${code}] ${errorMessage}`);
  if (code === "NOT_FOUND") {
    set.status = 404;
    return {
      success: false,
      error: {
        code: "NOT_FOUND",
        message: "Endpoint not found"
      }
    };
  }
  if (code === "VALIDATION") {
    set.status = 400;
    return {
      success: false,
      error: {
        code: "VALIDATION_ERROR",
        message: errorMessage
      }
    };
  }
  set.status = 500;
  return {
    success: false,
    error: {
      code: "INTERNAL_ERROR",
      message: errorMessage
    }
  };
}).listen(PORT);
console.log(`\uD83D\uDE80 Server is running on http://localhost:${PORT}`);
console.log(`\uD83D\uDCD6 API base path: ${API_BASE_PATH}`);
console.log(`\uD83D\uDD27 Environment: ${"development"}`);
